from typing import List

class Solution:
    def mergeStones(self, stones: List[int], k: int) -> int:
        n = len(stones)
        if (n - 1) % (k - 1) != 0:
            return -1

        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + stones[i]

        INF = float('inf')
        # Initialize DP table: dp[i][j][m]
        dp = [[[INF] * (n + 1) for _ in range(n)] for __ in range(n)]

        for i in range(n):
            dp[i][i][1] = 0

        for l in range(2, n + 1):
            for i in range(n - l + 1):
                j = i + l - 1
                current_sum = prefix[j + 1] - prefix[i]

                for m in range(2, l + 1):
                    if (l - m) % (k - 1) != 0:
                        continue
                    min_cost = INF
                    for mid in range(i, j):
                        for m1 in range(1, m):
                            m2 = m - m1
                            left_len = mid - i + 1
                            right_len = j - mid
                            if (left_len - m1) % (k - 1) != 0 or (right_len - m2) % (k - 1) != 0:
                                continue
                            cost = dp[i][mid][m1] + dp[mid + 1][j][m2]
                            if cost < min_cost:
                                min_cost = cost
                    if min_cost != INF:
                        dp[i][j][m] = min_cost

                # Handle m=1 after other m's
                if (l - 1) % (k - 1) == 0:
                    m_needed = k
                    if m_needed <= l and dp[i][j][m_needed] != INF:
                        dp[i][j][1] = dp[i][j][m_needed] + current_sum
                else:
                    dp[i][j][1] = INF

        return dp[0][n - 1][1] if dp[0][n - 1][1] != INF else -1
